/**
 * Translate a string key to the given language, with optional parameter substitution.
 * Falls back to English if translation not found for the requested language.
 */
export function t(key: string, lang: string, params?: Record<string, string | number>): string {
  const entry = S[key];
  if (!entry) return key;
  let text = entry[lang] ?? entry.hi ?? entry.en ?? key;
  if (params) {
    for (const [k, v] of Object.entries(params)) {
      text = text.replace(`{${k}}`, String(v));
    }
  }
  return text;
}

/** All available string keys */
export const StringKeys = Object.keys(S);

/** Export raw translations for direct access if needed */
export { S as Strings };
